diff --git a/llvm/lib/Analysis/InstructionSimplify.cpp b/llvm/lib/Analysis/InstructionSimplify.cpp
index 2a1218a683ca..ef2432817fba 100644
--- a/llvm/lib/Analysis/InstructionSimplify.cpp
+++ b/llvm/lib/Analysis/InstructionSimplify.cpp
@@ -1863,6 +1863,38 @@ static Value *simplifyAndOfICmps(ICmpInst *Op0, ICmpInst *Op1,
     return X;
   if (Value *X = simplifyAndOfICmpsWithAdd(Op1, Op0, Q.IIQ))
     return X;
+  // (icmp uge (add A, B), A) & (icmp uge (add A, B), B) --> (icmp uge (add A, B), A)
+  // (icmp ule A, (add A, B)) & (icmp ule B, (add A, B)) --> (icmp ule A, (add A, B))
+  // Both conditions test for no unsigned overflow of A + B and are equivalent.
+  {
+    ICmpInst::Predicate Pred0 = Op0->getPredicate();
+    ICmpInst::Predicate Pred1 = Op1->getPredicate();
+    Value *Op0_0 = Op0->getOperand(0), *Op0_1 = Op0->getOperand(1);
+    Value *Op1_0 = Op1->getOperand(0), *Op1_1 = Op1->getOperand(1);
+    
+    // Normalize to have the add on the left side
+    if (Pred0 == ICmpInst::ICMP_ULE) {
+      std::swap(Op0_0, Op0_1);
+      Pred0 = ICmpInst::ICMP_UGE;
+    }
+    if (Pred1 == ICmpInst::ICMP_ULE) {
+      std::swap(Op1_0, Op1_1);
+      Pred1 = ICmpInst::ICMP_UGE;
+    }
+    
+    if (Pred0 == ICmpInst::ICMP_UGE && Pred1 == ICmpInst::ICMP_UGE &&
+        Op0_0 == Op1_0) {
+      if (auto *Add = dyn_cast<BinaryOperator>(Op0_0)) {
+        if (Add->getOpcode() == Instruction::Add) {
+          Value *AddOp0 = Add->getOperand(0);
+          Value *AddOp1 = Add->getOperand(1);
+          if ((Op0_1 == AddOp0 && Op1_1 == AddOp1) ||
+              (Op0_1 == AddOp1 && Op1_1 == AddOp0))
+            return Op0;
+        }
+      }
+    }
+  }

   return nullptr;
 }
@@ -1939,6 +1971,38 @@ static Value *simplifyOrOfICmps(ICmpInst *Op0, ICmpInst *Op1,
     return X;
   if (Value *X = simplifyOrOfICmpsWithAdd(Op1, Op0, Q.IIQ))
     return X;
+  // (icmp ult (add A, B), A) | (icmp ult (add A, B), B) --> (icmp ult (add A, B), A)
+  // (icmp ugt A, (add A, B)) | (icmp ugt B, (add A, B)) --> (icmp ugt A, (add A, B))
+  // Both conditions test for unsigned overflow of A + B and are equivalent.
+  {
+    ICmpInst::Predicate Pred0 = Op0->getPredicate();
+    ICmpInst::Predicate Pred1 = Op1->getPredicate();
+    Value *Op0_0 = Op0->getOperand(0), *Op0_1 = Op0->getOperand(1);
+    Value *Op1_0 = Op1->getOperand(0), *Op1_1 = Op1->getOperand(1);
+    
+    // Normalize to have the add on the left side
+    if (Pred0 == ICmpInst::ICMP_UGT) {
+      std::swap(Op0_0, Op0_1);
+      Pred0 = ICmpInst::ICMP_ULT;
+    }
+    if (Pred1 == ICmpInst::ICMP_UGT) {
+      std::swap(Op1_0, Op1_1);
+      Pred1 = ICmpInst::ICMP_ULT;
+    }
+    
+    if (Pred0 == ICmpInst::ICMP_ULT && Pred1 == ICmpInst::ICMP_ULT &&
+        Op0_0 == Op1_0) {
+      if (auto *Add = dyn_cast<BinaryOperator>(Op0_0)) {
+        if (Add->getOpcode() == Instruction::Add) {
+          Value *AddOp0 = Add->getOperand(0);
+          Value *AddOp1 = Add->getOperand(1);
+          if ((Op0_1 == AddOp0 && Op1_1 == AddOp1) ||
+              (Op0_1 == AddOp1 && Op1_1 == AddOp0))
+            return Op0;
+        }
+      }
+    }
+  }

   return nullptr;
 }
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index 703065280096..a404df364986 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -3092,6 +3092,20 @@ Value *InstCombinerImpl::foldAndOrOfICmps(ICmpInst *LHS, ICmpInst *RHS,
       return getNewICmpValue(Code, IsSigned, LHS0, LHS1, Builder);
     }
   }
+  // (icmp ult (add A, B), A) | (icmp ult (add A, B), B) --> (icmp ult (add A, B), A)
+  // Both conditions are equivalent: they test for unsigned overflow of A + B.
+  if (!IsAnd && PredL == ICmpInst::ICMP_ULT && PredR == ICmpInst::ICMP_ULT &&
+      LHS0 == RHS0) {
+    if (auto *Add = dyn_cast<BinaryOperator>(LHS0)) {
+      if (Add->getOpcode() == Instruction::Add) {
+        Value *AddOp0 = Add->getOperand(0);
+        Value *AddOp1 = Add->getOperand(1);
+        if ((LHS1 == AddOp0 && RHS1 == AddOp1) ||
+            (LHS1 == AddOp1 && RHS1 == AddOp0))
+          return LHS;
+      }
+    }
+  }

   // handle (roughly):
   // (icmp ne (A & B), C) | (icmp ne (A & D), E)
